#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>
#include <sys/socket.h>
#include <fcntl.h>

#define BUFFER_SIZE 256

void send_fd(int sock_fd, int fd_to_send) {
 struct msghdr msg = {0};
 char buf[CMSG_SPACE(sizeof(int))];
 struct cmsghdr *cmsg;

 // Dummy data to send
 char data[] = "File descriptor passed!";
 struct iovec iov[1];
 iov[0].iov_base = data;
 iov[0].iov_len = strlen(data);
 msg.msg_iov = iov;
 msg.msg_iovlen = 1;

 // Setup control message for SCM_RIGHTS
 msg.msg_control = buf;
 msg.msg_controllen = sizeof(buf);

 cmsg = CMSG_FIRSTHDR(&msg);
 cmsg->cmsg_level = SOL_SOCKET;
 cmsg->cmsg_type = SCM_RIGHTS;
 cmsg->cmsg_len = CMSG_LEN(sizeof(int));

 // Copy file descriptor into control message
 *((int *)CMSG_DATA(cmsg)) = fd_to_send;

 // Send the file descriptor
 if (sendmsg(sock_fd, &msg, 0) < 0) {
 perror("sendmsg failed");
 exit(1);
 }
}

int receive_fd(int sock_fd) {
 struct msghdr msg = {0};
 char buf[CMSG_SPACE(sizeof(int))];
 char data[BUFFER_SIZE];
 struct cmsghdr *cmsg;
 int received_fd = -1;
 struct iovec iov[1];

 // Setup iovec for data
 iov[0].iov_base = data;
 iov[0].iov_len = BUFFER_SIZE;
 msg.msg_iov = iov;
 msg.msg_iovlen = 1;

 // Setup control message buffer
 msg.msg_control = buf;
 msg.msg_controllen = sizeof(buf);

 if (recvmsg(sock_fd, &msg, 0) < 0) {
 perror("recvmsg failed");
 return -1;
 }

 // Find SCM_RIGHTS in control messages
 for (cmsg = CMSG_FIRSTHDR(&msg); cmsg != NULL;
 cmsg = CMSG_NXTHDR(&msg, cmsg)) {
 if (cmsg->cmsg_level == SOL_SOCKET &&
 cmsg->cmsg_type == SCM_RIGHTS) {
 received_fd = *((int *)CMSG_DATA(cmsg));
 break;
 }
 }

 return received_fd;
}

int main() {
 int sv[2]; // Socket pair for parent-child communication
 int file_fd;
 pid_t pid;

 // Create socket pair (bidirectional)
 if (socketpair(AF_UNIX, SOCK_STREAM, 0, sv) < 0) {
 perror("socketpair failed");
 exit(1);
 }

 // Open a file to pass
 file_fd = open("test.txt", O_RDONLY);
 if (file_fd < 0) {
 perror("open failed");
 exit(1);
 }

 pid = fork();

 if (pid == 0) {
 // Child process
 close(sv[1]); // Close one end of socket pair

 // Receive file descriptor from parent
 int received_fd = receive_fd(sv[0]);
 if (received_fd >= 0) {
 char buffer[100];
 ssize_t n = read(received_fd, buffer, sizeof(buffer) - 1);
 if (n > 0) {
 buffer[n] = '\0';
 printf("Child received and read from FD %d: %s\n", received_fd, buffer);
 }
 close(received_fd); // Close received FD
 }
 close(sv[0]);
 exit(0);
 } else {
 // Parent process
 close(sv[0]); // Close one end of socket pair

 // Send file descriptor to child
 send_fd(sv[1], file_fd);
 close(file_fd); // Close original after sending

 wait(NULL); // Wait for child
 close(sv[1]);
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/socket.h>
#include <sys/types.h>
#include <netinet/in.h>

#define BACKLOG 5

// Global variables for socket pair
int parent_child_sock[2];

void setup_privilege_separation() {
 // Create socket pair for communication between parent and child
 if (socketpair(AF_UNIX, SOCK_STREAM, 0, parent_child_sock) < 0) {
 perror("socketpair failed");
 exit(1);
 }
}

void drop_privileges() {
 // Drop root privileges after accepting connection
 // Implementation would use setuid(), setgid() to become unprivileged user
 // For demonstration purposes only
 printf("Dropping privileges to unprivileged user...\n");
}

void handle_request(int client_fd) {
 // This runs in the unprivileged child
 char buffer[1024];
 ssize_t n;

 // Process the request using client_fd
 n = read(client_fd, buffer, sizeof(buffer));
 if (n > 0) {
 // Handle request data
 write(client_fd, "HTTP/1.1 200 OK\n", 16);
 }
}

int main() {
 int server_fd, client_fd;
 struct sockaddr_in client_addr;
 socklen_t client_len = sizeof(client_addr);
 pid_t pid;

 // Create listening socket (requires root for binding to port 80)
 server_fd = socket(AF_INET, SOCK_STREAM, 0);
 // ... bind and listen (requires root) ...

 setup_privilege_separation();

 while (1) {
 // Accept connection (still running as root)
 client_fd = accept(server_fd, &client_addr, &client_len);
 if (client_fd < 0) continue;

 pid = fork();

 if (pid == 0) {
 // Child process - will handle request
 close(server_fd);
 close(parent_child_sock[0]);

 // Drop privileges BEFORE using the socket
 drop_privileges();

 // Receive the client socket from parent via FD passing
 // (simplified - would use recvmsg with SCM_RIGHTS)

 handle_request(client_fd);
 close(client_fd);
 close(parent_child_sock[1]);
 exit(0);
 } else {
 // Parent process - stays privileged
 // Pass client_fd to child
 // (simplified - would use sendmsg with SCM_RIGHTS)

 // Close child's reference - parent doesn't need it anymore
 close(client_fd);
 close(parent_child_sock[1]);

 // Continue accepting new connections
 wait(NULL); // Or use SIGCHLD handler
 }
 }

 return 0;
}
